import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, Avatar } from 'decantr/components';
import { link } from 'decantr/router';

code.example:
function PostList() {
  const { div, h3, p, span, time } = tags;
  const posts = [
    { slug: 'design-systems', category: 'Design', readTime: '5 min', title: 'Building Design Systems at Scale', excerpt: 'How to create and maintain design systems that grow with your organization.', author: { avatar: '', name: 'Alice Chen' }, date: 'Mar 10, 2026' },
    { slug: 'reactive-state', category: 'Engineering', readTime: '8 min', title: 'Reactive State Management Patterns', excerpt: 'Exploring signals, stores, and effects for predictable UI state.', author: { avatar: '', name: 'Bob Patel' }, date: 'Mar 8, 2026' },
    { slug: 'accessibility', category: 'Design', readTime: '6 min', title: 'Accessibility Beyond Compliance', excerpt: 'Moving past checklists to create truly inclusive experiences.', author: { avatar: '', name: 'Carol Liu' }, date: 'Mar 5, 2026' }
  ];

  return div({ class: css('_flex _col _gap4 _p4') },
    ...posts.map(post =>
      link({ href: `/blog/${post.slug}`, class: css('_nounder') },
        Card({ class: css('_flex _col _gap3') },
          Card.Body({},
            div({ class: css('_flex _aic _gap2 _mb2') },
              Badge({}, post.category),
              span({ class: css('_textxs _fgmuted') }, post.readTime)
            ),
            h3({ class: css('_heading5') }, post.title),
            p({ class: css('_textsm _fgmuted _clamp2') }, post.excerpt),
            div({ class: css('_flex _aic _gap2 _mt3') },
              Avatar({ src: post.author.avatar, name: post.author.name, size: 'sm' }),
              span({ class: css('_textsm') }, post.author.name),
              time({ class: css('_textsm _fgmuted _mla') }, post.date)
            )
          )
        )
      )
    )
  );
}
